import numpy as np
import cv2


class _DummySam:
    def __init__(self, checkpoint=None):
        self.checkpoint = checkpoint
    def to(self, device=None):
        return self
    def eval(self):
        return self


sam_model_registry = {"vit_t": lambda checkpoint=None: _DummySam(checkpoint)}


class SamPredictor:
    def __init__(self, model):
        self.model = model
        self.image = None
    def set_image(self, image):
        self.image = image
        self.H, self.W = image.shape[:2]
    def predict(self, box=None, multimask_output=False):
        # Return an ellipse filling the box to emulate a refined blob mask.
        x0, y0, x1, y1 = [int(round(v)) for v in box]
        m = np.zeros((self.H, self.W), dtype=bool)
        cx, cy = (x0 + x1) // 2, (y0 + y1) // 2
        ax, ay = max(1, (x1 - x0) // 2), max(1, (y1 - y0) // 2)
        canvas = np.zeros((self.H, self.W), dtype=np.uint8)
        cv2.ellipse(canvas, (cx, cy), (ax, ay), 0, 0, 360, 1, -1)
        m = canvas.astype(bool)
        score = 0.5 + 0.5 * np.random.rand()
        return m[None], np.array([score], dtype=np.float32), m[None].astype(np.float32)

